// DJ OPUS - MEGA MIX v3
// Robert Miles vibes + real vocals
setcps(138/60/4)

samples('shabda:choir:6,vocal:4,diva:4,female voice:3')

// === YOUR DECK ===
let kickVol = slider(0.8, 0, 1.1, 0.01, "KICK")
let bassVol = slider(0.4, 0, 0.7, 0.01, "BASS")
let hatVol = slider(0.3, 0, 0.5, 0.01, "HATS")
let pianoVol = slider(0.4, 0, 0.6, 0.01, "PIANO Lead")
let padVol = slider(0.3, 0, 0.5, 0.01, "PAD Depth")
let sweepFilter = slider(2000, 200, 10000, 10, "FILTER SWEEP")
let vocalVol = slider(0.4, 0, 0.8, 0.01, "VOCALS")
let delayMix = slider(0.3, 0, 0.7, 0.01, "DELAY Wash")

// KICK
let kick = s("bd").bank("RolandTR909")
  .gain(kickVol)
  .struct("x x x x")

// CLAP
let clap = s("cp").bank("RolandTR909")
  .gain(0.5)
  .struct("~ x ~ x")
  .room(0.2)

// HATS
let hats = s("hh").bank("RolandTR909")
  .gain(hatVol)
  .struct("~ x ~ x ~ x ~ x")

// BASS
let bass = note("<a1 a1 e1 e1 f1 f1 d1 d1>".slow(2))
  .s("sawtooth")
  .cutoff(perlin.range(200, 1200).slow(8))
  .resonance(10)
  .decay(0.3)
  .sustain(0.1)
  .gain(bassVol)

// PIANO LEAD - dreamy
let piano = note("a4 ~ e5 c5 ~ ~ a4 ~ ~ e4 a4 c5 ~ e5 ~ ~".slow(2))
  .s("triangle")
  .cutoff(sweepFilter)
  .resonance(2)
  .attack(0.01)
  .decay(0.6)
  .sustain(0.1)
  .gain(pianoVol)
  .delay(delayMix)
  .delaytime(3/8)
  .delayfeedback(0.45)
  .room(0.6)

// PAD - warm bed
let pad = note("<[a2,e3] [e2,b2] [f2,c3] [d2,a2]>".slow(4))
  .s("sawtooth")
  .cutoff(perlin.range(300, 2000).slow(16))
  .resonance(5)
  .attack(1.5)
  .decay(2)
  .sustain(0.5)
  .release(2)
  .gain(padVol)
  .room(0.85)
  .size(0.9)

// CHOIR - slow cycling through samples with reverb
let choirVox = s("<choir:0 choir:1 choir:2 choir:3 choir:4 choir:5>".slow(4))
  .gain(vocalVol)
  .room(0.9)
  .size(0.9)
  .cutoff(sweepFilter)
  .speed(0.8)

// DIVA - layered on top
let divaVox = s("<diva:0 diva:1>".slow(8))
  .gain(vocalVol)
  .room(0.85)
  .size(0.9)
  .speed(0.7)

// VOCAL hits
let vocalHit = s("<vocal:0 vocal:1 vocal:2 vocal:3>".slow(2))
  .gain(vocalVol)
  .room(0.7)
  .delay(0.4)
  .delaytime(3/8)
  .delayfeedback(0.35)
  .speed(0.9)

stack(kick, clap, hats, bass, piano, pad, choirVox, divaVox, vocalHit)
